/*
 * NVIDIA GPU Device Properties Query
 * Compile: nvcc -o gpu_query gpu_query.cu
 * This program queries and displays all major GPU properties
 */

#include <stdio.h>
#include <cuda_runtime.h>

// Macro for checking CUDA errors
#define CUDA_CHECK(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 fprintf(stderr, "CUDA error at %s:%d: %s\n", \
 __FILE__, __LINE__, cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

// Function to map compute capability to architecture name
const char* get_architecture_name(int major, int minor) {
 if (major == 1) return "Tesla";
 if (major == 2) return "Fermi";
 if (major == 3) return "Kepler";
 if (major == 5) return "Maxwell";
 if (major == 6) return "Pascal";
 if (major == 7) return (minor == 0) ? "Volta" : "Turing";
 if (major == 8) return "Ampere";
 if (major == 9) return "Hopper";
 if (major >= 10) return "Blackwell";
 return "Unknown";
}

// Function to display feature availability based on compute capability
void display_features(int major, int minor) {
 printf(" Available Features:\n");

 // Dynamic Parallelism: CC 3.0+
 printf(" Dynamic Parallelism: %s\n", 
 (major >= 3) ? "YES" : "NO");

 // Unified Memory: CC 6.0+
 printf(" Unified Memory: %s\n", 
 (major >= 6) ? "YES" : "NO");

 // Tensor Cores: CC 7.0+
 printf(" Tensor Cores: %s\n", 
 (major >= 7) ? "YES" : "NO");

 // RT Cores: CC 7.5+ (Turing)
 printf(" RT Cores (Ray Tracing): %s\n", 
 (major == 7 && minor >= 5) ? "YES" : "NO");

 // Async Copy: CC 8.0+
 printf(" Async Memory Copy: %s\n", 
 (major >= 8) ? "YES" : "NO");

 // FP16 at full rate: CC 6.0+
 printf(" FP16 Support: %s\n", 
 (major >= 6) ? "YES (full rate)" : "NO");

 // Thread Block Clusters: CC 9.0+
 printf(" Thread Block Clusters: %s\n", 
 (major >= 9) ? "YES" : "NO");
}

// Function to print device properties
void print_device_properties(int dev, cudaDeviceProp *prop) {
 printf("========================================\n");
 printf("Device %d: %s\n", dev, prop->name);
 printf("========================================\n");

 // Compute Capability
 printf("Compute Capability: %d.%d\n", prop->major, prop->minor);
 printf("Architecture: %s\n", get_architecture_name(prop->major, prop->minor));

 // Processing Units
 printf("\n--- Processing Units ---\n");
 printf("SM Count: %d\n", prop->multiProcessorCount);
 printf("CUDA Cores per SM: %s\n", 
 prop->major >= 8 ? "128" : 
 prop->major >= 7 ? "64" : 
 prop->major >= 5 ? "128" : 
 prop->major >= 3 ? "192" : "8"); // Approximate

 // Thread Configuration Limits
 printf("\n--- Thread Configuration ---\n");
 printf("Max Threads per Block: %d\n", prop->maxThreadsPerBlock);
 printf("Max Threads per SM: %d\n", prop->maxThreadsPerMultiProcessor);
 printf("Warp Size: %d\n", prop->warpSize);
 printf("Max Block Dimensions: [%d, %d, %d]\n",
 prop->maxThreadsDim[0], prop->maxThreadsDim[1], prop->maxThreadsDim[2]);
 printf("Max Grid Dimensions: [%d, %d, %d]\n",
 prop->maxGridSize[0], prop->maxGridSize[1], prop->maxGridSize[2]);

 // Memory Information
 printf("\n--- Memory ---\n");
 printf("Global Memory: %.2f GB\n", 
 prop->totalGlobalMem / (1024.0 * 1024.0 * 1024.0));
 printf("Shared Memory per Block: %zu KB\n", 
 prop->sharedMemPerBlock / 1024);
 printf("Shared Memory per SM: %zu KB\n", 
 prop->sharedMemPerMultiprocessor / 1024);
 printf("Registers per Block: %d\n", prop->regsPerBlock);
 printf("Registers per SM: %d\n", prop->regsPerMultiprocessor);
 printf("L2 Cache Size: %d KB\n", prop->l2CacheSize / 1024);
 printf("Constant Memory: %zu KB\n", prop->totalConstMem / 1024);

 // Clock Rates
 printf("\n--- Performance ---\n");
 printf("GPU Clock Rate: %.2f GHz\n", prop->clockRate / 1e6);
 printf("Memory Clock Rate: %.2f GHz\n", prop->memoryClockRate / 1e6);
 printf("Memory Bus Width: %d bits\n", prop->memoryBusWidth);
 printf("Memory Bandwidth: %.2f GB/s\n",
 2.0 * prop->memoryClockRate * prop->memoryBusWidth / 8 / 1e6);

 // Display feature availability
 display_features(prop->major, prop->minor);
}

int main(int argc, char *argv[]) {
 int deviceCount;

 // Get number of CUDA-capable devices
 CUDA_CHECK(cudaGetDeviceCount(&deviceCount));

 if (deviceCount == 0) {
 printf("No CUDA-capable devices found.\n");
 return 0;
 }

 printf("Found %d CUDA-capable device(s)\n\n", deviceCount);

 // Query each device
 for (int dev = 0; dev < deviceCount; dev++) {
 cudaDeviceProp prop;
 CUDA_CHECK(cudaGetDeviceProperties(&prop, dev));
 print_device_properties(dev, &prop);
 printf("\n");
 }

 // Display CUDA version
 int cudaVersion;
 CUDA_CHECK(cudaDriverGetVersion(&cudaVersion));
 printf("CUDA Driver Version: %d.%d\n", 
 cudaVersion / 1000, (cudaVersion % 1000) / 10);

 CUDA_CHECK(cudaRuntimeGetVersion(&cudaVersion));
 printf("CUDA Runtime Version: %d.%d\n", 
 cudaVersion / 1000, (cudaVersion % 1000) / 10);

 return 0;
}

/*
 * CUDA Compilation for Specific Compute Capabilities
 * Demonstrates different compilation strategies and conditional code
 * 
 * Compilation examples:
 * nvcc -arch=sm_70 basic.cu # Target Volta (CC 7.0)
 * nvcc -arch=sm_80 -gencode arch=sm_80 basic.cu # Target Ampere
 * nvcc -gencode arch=sm_70,code=sm_70 \ # Fat binary for multiple
 * -gencode arch=sm_80,code=sm_80 \n * -gencode arch=sm_90,code=sm_90 basic.cu
 */

#include <stdio.h>
#include <cuda_runtime.h>

// ============================================================================
// METHOD 1: Runtime Query - Most Flexible
// ============================================================================

__global__ void kernel_runtime_check() {
 int tid = blockIdx.x * blockDim.x + threadIdx.x;
 printf("Thread %d executing on SM %d\n", tid, blockIdx.x);
}

void demonstrate_runtime_query() {
 printf("=== Method 1: Runtime Query ===\n");

 cudaDeviceProp prop;
 cudaGetDeviceProperties(&prop, 0);

 int major = prop.major;
 int minor = prop.minor;

 printf("Device Compute Capability: %d.%d\n", major, minor);

 // Runtime feature detection
 if (major >= 7) {
 printf("Tensor Cores available - using optimized kernel\n");
 }
 if (major >= 8) {
 printf("Async copy available - using async operations\n");
 }
 if (major >= 9) {
 printf("Thread Block Clusters available\n");
 }

 kernel_runtime_check<<<1, 4>>>();
 cudaDeviceSynchronize();
 printf("\n");
}

// ============================================================================
// METHOD 2: Compile-time Conditional with __CUDA_ARCH__
// __CUDA_ARCH__ is only defined during device code compilation
// ============================================================================

#if defined(__CUDA_ARCH__)
 // This code compiles differently based on target architecture
 __device__ int get_architecture_id() {
 #if __CUDA_ARCH__ >= 900
 return 900; // Hopper
 #elif __CUDA_ARCH__ >= 800
 return 800; // Ampere
 #elif __CUDA_ARCH__ >= 750
 return 750; // Turing
 #elif __CUDA_ARCH__ >= 700
 return 700; // Volta
 #elif __CUDA_ARCH__ >= 600
 return 600; // Pascal
 #elif __CUDA_ARCH__ >= 500
 return 500; // Maxwell
 #elif __CUDA_ARCH__ >= 300
 return 300; // Kepler
 #elif __CUDA_ARCH__ >= 200
 return 200; // Fermi
 #else
 return 100; // Tesla
 #endif
 }
#else
 // Host code fallback
 __device__ int get_architecture_id() { return 0; }
#endif

__global__ void kernel_show_arch() {
 printf("Kernel compiled for arch: %d\n", get_architecture_id());
}

// ============================================================================
// METHOD 3: Architecture-Specific Kernel Specialization
// ============================================================================

// Define different kernels for different architectures
#if __CUDA_ARCH__ >= 800
 // Ampere and newer: Use tensor cores via wmma
 __global__ void matrix_kernel_ampere(float *data, int size) {
 int idx = blockIdx.x * blockDim.x + threadIdx.x;
 if (idx < size) {
 // Ampere: Use 3rd gen tensor cores, async copy
 data[idx] = data[idx] * 2.0f; // Simplified
 }
 }
 #define MATRIX_KERNEL matrix_kernel_ampere
#elif __CUDA_ARCH__ >= 700
 // Volta/Turing: Use 1st/2nd gen tensor cores
 __global__ void matrix_kernel_volta(float *data, int size) {
 int idx = blockIdx.x * blockDim.x + threadIdx.x;
 if (idx < size) {
 data[idx] = data[idx] * 2.0f;
 }
 }
 #define MATRIX_KERNEL matrix_kernel_volta
#else
 // Older architectures: Standard CUDA
 __global__ void matrix_kernel_legacy(float *data, int size) {
 int idx = blockIdx.x * blockDim.x + threadIdx.x;
 if (idx < size) {
 data[idx] = data[idx] * 2.0f;
 }
 }
 #define MATRIX_KERNEL matrix_kernel_legacy
#endif

// ============================================================================
// METHOD 4: Host-side Architecture Detection with cudaFuncGetAttributes
// ============================================================================

void demonstrate_compilation_methods() {
 printf("=== Method 2: Compile-time __CUDA_ARCH__ ===\n");
 kernel_show_arch<<<1, 1>>>();
 cudaDeviceSynchronize();

 printf("\n=== Method 3: Architecture-Specific Kernels ===\n");

 float *d_data;
 cudaMalloc(&d_data, 100 * sizeof(float));

 // Launch the appropriately compiled kernel
 MATRIX_KERNEL<<<10, 10>>>(d_data, 100);
 cudaDeviceSynchronize();

 printf("\n=== Method 4: cudaFuncGetAttributes ===\n");

 cudaFuncAttributes attr;
 cudaFuncGetAttributes(&attr, (const void*)MATRIX_KERNEL);

 printf("Kernel shared memory: %zu bytes\n", attr.sharedSizeBytes);
 printf("Kernel registers: %d\n", attr.numRegs);
 printf("Kernel max threads: %d\n", attr.maxThreadsPerBlock);

 cudaFree(d_data);
}

// ============================================================================
// MAIN: Demonstrate all methods
// ============================================================================

int main() {
 printf("CUDA Compute Capability Compilation Demo\n");
 printf("==========================================\n\n");

 // Check current device
 cudaDeviceProp prop;
 cudaGetDeviceProperties(&prop, 0);
 printf("Running on: %s (CC %d.%d)\n\n", prop.name, prop.major, prop.minor);

 // Run demonstrations
 demonstrate_runtime_query();
 demonstrate_compilation_methods();

 printf("\n=== Compilation Flag Reference ===\n");
 printf("-arch=sm_XX : Set PTX ISA (minimum for JIT)\n");
 printf("-gencode arch=sm_XX,code=sm_XX : Embed SASS for specific arch\n");
 printf("-gencode arch=sm_XX,code=compute_XX : Embed PTX for forward compat\n");
 printf("\nExample multi-target:\n");
 printf(" nvcc -gencode arch=sm_70,code=sm_70 \\\n");
 printf(" -gencode arch=sm_80,code=sm_80 \\\n");
 printf(" -gencode arch=sm_90,code=sm_90 \\\n");
 printf(" -o program program.cu\n");

 return 0;
}
